function formaterDate(dateStr, langue) {
  if (!dateStr) return 'N/A';
  const date = new Date(dateStr);
  const locale = langue === 'ARA' ? 'ar-MA' : langue === 'ENG' ? 'en-US' : 'fr-FR';
  return date.toLocaleDateString(locale, { year: 'numeric', month: '2-digit', day: '2-digit' });
}

function formaterDateHeure(dateStr, langue) {
  if (!dateStr) return 'N/A';
  const date = new Date(dateStr);
  const locale = langue === 'ARA' ? 'ar-MA' : langue === 'ENG' ? 'en-US' : 'fr-FR';
  return date.toLocaleString(locale, { year: 'numeric', month: '2-digit', day: '2-digit', hour: '2-digit', minute: '2-digit' });
}

function getEmoji(jours) {
  if (jours <= 2) return '🔴';
  if (jours === 3) return '🟠';
  if (jours === 4) return '🟡';
  if (jours <= 8) return '🔵';
  return '🟢';
}

function genererMessagePrincipal(data) {
  const langue = data.meta.langue_message || 'FRA';
  const T = TEMPLATES[langue] || TEMPLATES.FRA;
  const destinataire = data.destinataire_principal;
  const stats = data.statistiques;
  const attestations = data.attestations;
  const type = data.type_destinataire;

  let emailSubject = `${T.sujet_email[type] || T.sujet_email.SALARIE} - ${stats.total_attestations} décharge(s)`;

  let emailBody = `${T.salutation} ${destinataire.prenom} ${destinataire.nom},\n\n`;
  emailBody += `${T.introduction[type]}\n\n`;
  emailBody += `═══════════════════════════════════════════════════════════════\n`;
  emailBody += `📊 ${T.section_stats}\n`;
  emailBody += `═══════════════════════════════════════════════════════════════\n\n`;
  emailBody += `${getEmoji(stats.jours_min)} Niveau: ${data.niveau_escalade}\n`;
  emailBody += `${T.total}: ${stats.total_attestations}\n`;
  emailBody += `${T.delai_min}: ${stats.jours_min} ${T.jours}\n`;
  emailBody += `${T.delai_total}: ${stats.delai_total} ${T.jours}\n`;

  if (type === 'DGA' || type === 'BAALLAH') {
    emailBody += `${T.seuil_mi_delai}: ${stats.seuil_mi_delai} ${T.jours}\n`;
  }

  if (type !== 'SALARIE' && type !== 'DGA' && type !== 'BAALLAH') {
    emailBody += `\n${T.salarie_concerne}: ${data.salarie.prenom} ${data.salarie.nom} (${data.salarie.code})\n`;
  }

  emailBody += `\n═══════════════════════════════════════════════════════════════\n`;
  emailBody += `📋 ${T.section_attestations}\n`;
  emailBody += `═══════════════════════════════════════════════════════════════\n\n`;

  attestations.forEach((att, index) => {
    emailBody += `${index + 1}. ${getEmoji(att.jours_restants)} ${att.numero_attestation}\n`;
    emailBody += `   📅 ${T.date_creation}: ${formaterDateHeure(att.date_creation_attestation, langue)}\n`;
    emailBody += `   🧑 ${T.salarie_concerne}: ${att.salarie_concerne.prenom} ${att.salarie_concerne.nom} (${att.salarie_concerne.code})\n`;
    emailBody += `   ⏰ ${T.delai}: ${att.jours_restants} ${T.jours} ${T.restant} (${T.limite}: ${formaterDate(att.date_limite, langue)})\n`;
    if (att.jours_restants <= 2) emailBody += `   🚨 ${T.urgent}\n`;
    emailBody += `\n`;
  });

  emailBody += `═══════════════════════════════════════════════════════════════\n`;
  if (stats.jours_min <= 2) {
    emailBody += `🚨 ${T.action_requise}: ${T.urgent}\n`;
  } else if (type === 'DGA' || type === 'BAALLAH') {
    emailBody += `📌 ${T.instruction_mi_delai}\n`;
  } else {
    emailBody += `📌 ${T.instruction}\n`;
  }
  emailBody += `═══════════════════════════════════════════════════════════════\n\n`;
  emailBody += `📞 ${T.contact}:\n`;
  if (data.superieur && data.superieur.email) {
    emailBody += `   ${data.superieur.prenom} ${data.superieur.nom}\n`;
    emailBody += `   Email: ${data.superieur.email}\n`;
    emailBody += `   Tel: ${data.superieur.telephone || 'N/A'}\n`;
  }
  if (data.salarie && data.salarie.email) {
    emailBody += `   ${T.salarie_concerne}: ${data.salarie.prenom} ${data.salarie.nom}\n`;
    emailBody += `   Email: ${data.salarie.email}\n`;
    emailBody += `   Tel: ${data.salarie.telephone || 'N/A'}\n`;
  }
  emailBody += `\n${T.cordialement},\n\n${T.signature}\n\n`;
  emailBody += `━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━\n`;
  emailBody += `🤖 ${T.message_auto} - ${formaterDate(new Date().toISOString(), langue)}\n`;
  if (type === 'PDG')     emailBody += `🔴 Notification URGENTE envoyée au PDG\n`;
  if (type === 'DGA')     emailBody += `🟠 Notification envoyée au DGA (seuil: délai/2 = ${stats.seuil_mi_delai}j)\n`;
  if (type === 'BAALLAH') emailBody += `🟠 Notification envoyée à Baallah (seuil: délai/2 = ${stats.seuil_mi_delai}j)\n`;
  emailBody += `${T.ne_pas_repondre}\n`;

  let telegramMessage = `${getEmoji(stats.jours_min)} *${T.sujet_email[type]}*\n`;
  telegramMessage += `━━━━━━━━━━━━━━━━━━━━━\n\n`;
  telegramMessage += `👤 *${destinataire.prenom} ${destinataire.nom}*\n\n`;
  telegramMessage += `📊 *${T.section_stats}*\n`;
  telegramMessage += `${T.total}: *${stats.total_attestations}*\n`;
  telegramMessage += `${T.delai_min}: *${stats.jours_min} ${T.jours}*\n\n`;
  telegramMessage += `📋 *${T.section_attestations}*\n\n`;
  attestations.slice(0, 5).forEach((att, index) => {
    telegramMessage += `${index + 1}. ${getEmoji(att.jours_restants)} *${att.numero_attestation}*\n`;
    telegramMessage += `   📅 ${formaterDate(att.date_creation_attestation, langue)}\n`;
    telegramMessage += `   🧑 ${att.salarie_concerne.prenom} ${att.salarie_concerne.nom}\n`;
    telegramMessage += `   ⏰ ${att.jours_restants} ${T.jours} ${T.restant}\n\n`;
  });
  if (attestations.length > 5) telegramMessage += `... et ${attestations.length - 5} autre(s) décharge(s)\n\n`;
  if (stats.jours_min <= 2) telegramMessage += `🚨 *${T.urgent}*\n\n`;

  return {
    email: { subject: emailSubject, body: emailBody },
    telegram: { text: telegramMessage, parse_mode: 'Markdown' }
  };
}

const results = [];

inputData.forEach(item => {
  const data = item.json;
  const messagesPrincipal = genererMessagePrincipal(data);

  const envoyer_cc_salarie   = (data.type_destinataire === 'SUPERIEUR' || data.type_destinataire === 'PDG');
  const envoyer_cc_superieur = (data.type_destinataire === 'PDG');

  results.push({
    json: {
      ...data,
      messages: messagesPrincipal,
      type_envoi: 'PRINCIPAL',
      destinataire_final: data.destinataire_principal,
      envoyer_cc_salarie,
      envoyer_cc_superieur,
      meta: { ...data.meta, langue_utilisee: data.meta.langue_message || 'FRA', date_generation: new Date().toISOString() }
    }
  });

  // CC pour SUPERIEUR
  if (data.type_destinataire === 'SUPERIEUR' && data.salarie && data.salarie.chat_id) {
    results.push({ json: { ...data, messages: messagesPrincipal, type_envoi: 'CC', destinataire_final: data.salarie, cc_pour_profil: 'SALARIE', envoyer_cc_salarie: true, envoyer_cc_superieur: false, meta: { ...data.meta, langue_utilisee: data.salarie.langue || 'FRA', date_generation: new Date().toISOString() } } });
  }
  // CC pour PDG
  if (data.type_destinataire === 'PDG') {
    if (data.superieur && data.superieur.chat_id) {
      results.push({ json: { ...data, messages: messagesPrincipal, type_envoi: 'CC', destinataire_final: data.superieur, cc_pour_profil: 'SUPERIEUR', envoyer_cc_salarie: false, envoyer_cc_superieur: true, meta: { ...data.meta, langue_utilisee: data.superieur.langue || 'FRA', date_generation: new Date().toISOString() } } });
    }
    if (data.salarie && data.salarie.chat_id) {
      results.push({ json: { ...data, messages: messagesPrincipal, type_envoi: 'CC', destinataire_final: data.salarie, cc_pour_profil: 'SALARIE', envoyer_cc_salarie: true, envoyer_cc_superieur: false, meta: { ...data.meta, langue_utilisee: data.salarie.langue || 'FRA', date_generation: new Date().toISOString() } } });
    }
  }
  // DGA, BAALLAH, FARHAT, SALARIE → pas de CC
});

